const raw = $input.first().json.content || $input.first().json.response || '';
const refMap = $('Format Data for LLM').first().json.ref_map || {};

let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  try {
    const cleanedStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
    parsed = JSON.parse(cleanedStr);
  } catch (err) {
    return [{ json: { response: raw } }];
  }
}

const greeting = parsed.greeting || '';
const signoff = parsed.signoff || '';
const outbound = parsed.outbound_activity_critique || {};
const inbox = parsed.inbox_and_leads_analysis || {};
const communityActions = Array.isArray(parsed.community_and_lead_actions) ? parsed.community_and_lead_actions : [];
const strategicDirectives = Array.isArray(parsed.strategic_writing_directives) ? parsed.strategic_writing_directives : [];

const outputs = [];

// 1. Outbound Activity Critique
if (outbound && (outbound.overview || (Array.isArray(outbound.bulletpoints) && outbound.bulletpoints.length > 0))) {
  let outboundMsg = '';
  if (greeting) {
    outboundMsg += `${greeting}\n\n`;
  }
  outboundMsg += `🧭 *1. Outbound Activity Critique* 🧭\n`;
  if (outbound.overview) {
    outboundMsg += `${outbound.overview}\n\n`;
  }
  if (Array.isArray(outbound.bulletpoints) && outbound.bulletpoints.length > 0) {
    outbound.bulletpoints.forEach(bullet => {
      outboundMsg += `• ${bullet}\n`;
    });
  }
  outputs.push({ json: { response: outboundMsg.trim() } });
}

// 2. Inbox & Leads Analysis
if (inbox && (inbox.overview || (Array.isArray(inbox.bulletpoints) && inbox.bulletpoints.length > 0))) {
  let inboxMsg = `📥 *2. Inbox & Leads Analysis* 📥\n`;
  if (inbox.overview) {
    inboxMsg += `${inbox.overview}\n\n`;
  }
  if (Array.isArray(inbox.bulletpoints) && inbox.bulletpoints.length > 0) {
    inbox.bulletpoints.forEach(bullet => {
      inboxMsg += `• ${bullet}\n`;
    });
  }
  outputs.push({ json: { response: inboxMsg.trim() } });
}

// 3. Community & Lead Actions
if (communityActions.length > 0) {
  let communityMsg = `🤝 *3. Community & Lead Actions* 🤝\n`;
  communityActions.forEach(action => {
    communityMsg += `• *${action.type || 'Action'}* with *${action.target || 'Community'}*:\n  _"${action.actionable_reply}"_\n`;
  });
  outputs.push({ json: { response: communityMsg.trim() } });
}

// 4. Strategic Writing Directives
if (strategicDirectives.length > 0) {
  let strategicMsg = `✍️ *4. Strategic Writing Directives* ✍️\n`;
  strategicDirectives.forEach(rec => {
    strategicMsg += `• ${rec}\n`;
  });
  if (signoff) {
    strategicMsg += `\n${signoff}`;
  }
  outputs.push({ json: { response: strategicMsg.trim() } });
} else if (signoff) {
  outputs.push({ json: { response: signoff } });
}

return outputs;
